#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;

struct Node{
    int op,l,r;
}qu[N];

struct TreeNode{
    int sl,sg,tag;
    bool res;
}t[N<<2];

int n,m,k,a[N];

TreeNode operator+(TreeNode x,TreeNode y){
    return {x.sl+y.sl,x.sg+y.sg,0,x.res|y.res};
}

void push_down(int cur,int l,int r){
    int mid=l+r>>1;
    if(t[cur].tag==1){
        t[cur*2]={0,mid-l+1,1,false};
        t[cur*2+1]={0,r-mid,1,false};
    }else if(t[cur].tag==-1){
        t[cur*2]={mid-l+1,0,-1,false};
        t[cur*2+1]={r-mid,0,-1,false};
    }
    t[cur].tag=0;
}

void build(int cur,int l,int r,int num){
	t[cur]={0,0,0,0};
    if(l==r){
        if(a[l]<num)
            t[cur].sl=1;
        else if(a[l]>num)
            t[cur].sg=1;
        else
            t[cur].res=true;
        return;
    }
    int mid=l+r>>1;
    build(cur*2,l,mid,num);
    build(cur*2+1,mid+1,r,num);
    t[cur]=t[cur*2]+t[cur*2+1];
}

TreeNode query(int cur,int l,int r,int x,int y){
    if(x<=l && r<=y)
        return t[cur];
    push_down(cur,l,r);
    int mid=l+r>>1;
    TreeNode res={0,0,0,false};
    if(x<=mid)
        res=res+query(cur*2,l,mid,x,y);
    if(y>mid)
        res=res+query(cur*2+1,mid+1,r,x,y);
    return res;
}

void modify(int cur,int l,int r,int x,int y,int tp){
    if(x<=l && r<=y){
        if(tp==1)
            t[cur]={0,r-l+1,1,false};
        else if(tp==-1)
            t[cur]={r-l+1,0,-1,false};
        else
            t[cur]={0,0,0,true};
        return;
    }
    push_down(cur,l,r);
    int mid=l+r>>1;
    if(x<=mid)
        modify(cur*2,l,mid,x,y,tp);
    if(y>mid)
        modify(cur*2+1,mid+1,r,x,y,tp);
    t[cur]=t[cur*2]+t[cur*2+1];
}

