int check(int num){
    build(1,1,n,num);
    for(int i=1;i<=m;i++){
    	TreeNode tmp=query(1,1,n,qu[i].l,qu[i].r);
    	if(qu[i].op==0){
    		if(tmp.sl)
    			modify(1,1,n,qu[i].l,qu[i].l+tmp.sl-1,-1);
    		if(tmp.res)
    			modify(1,1,n,qu[i].l+tmp.sl,qu[i].l+tmp.sl,0);
    		if(tmp.sg)
    			modify(1,1,n,qu[i].r-tmp.sg+1,qu[i].r,1);
		}else{
			if(tmp.sg)
    			modify(1,1,n,qu[i].l,qu[i].l+tmp.sg-1,1);
    		if(tmp.res)
    			modify(1,1,n,qu[i].l+tmp.sg,qu[i].l+tmp.sg,0);
    		if(tmp.sl)
    			modify(1,1,n,qu[i].r-tmp.sl+1,qu[i].r,-1);
		}
	}
	TreeNode tmp=query(1,1,n,k,k);
	if(tmp.sl)
		return -1;
	if(tmp.res)
		return 0;
	if(tmp.sg)
		return 1;
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    for(int i=1;i<=m;i++)
        scanf("%d%d%d",&qu[i].op,&qu[i].l,&qu[i].r);
    scanf("%d",&k);
    int l=1,r=n;
    while(l<r){
        int mid=l+r>>1,cmp=check(mid);
        if(cmp==0){
            printf("%d",mid);
            return 0;
        }else if(cmp==1)
            l=mid+1;
        else
            r=mid-1;
    }
    printf("%d",l);
    return 0;
}
